/**
 * @interface IPickFilter
 * @param {boolean} bFilterForExclude (optional)
 * @param {Array<string>} filterEntityTypes (optional)
 * @param {Array<Record<string, any>>} excludeEntities (optional)
 */
export interface IPickFilter {
    bFilterForExclude?: boolean;
    filterEntityTypes?: Array<string>;
    excludeEntities?: Array<Record<string, any>>;
}
/**
 * @interface IDefaultActionSetting
 * @param {IPickFilter} pickFilter (optional)
 * @param {string} selectionMode (optional)
 * @param {boolean} bEditPivotMode (optional)
 */
export interface IDefaultActionSetting {
    pickFilter?: IPickFilter;
    selectionMode?: string;
    bEditPivotMode?: boolean;
}
/**
 * @interface IBatchPlaceAsset
 * @param {number} yaw (optional)
 * @param {Array<number>} yawRandomRange (optional)
 * @param {number} scale (optional)
 * @param {Array<number>} scaleRandomRange (optional)
 * @param {Array<IAsset>} assets (optional)
 */
export interface IBatchPlaceAsset {
    yaw?: number;
    yawRandomRange?: Array<number>;
    scale?: number;
    scaleRandomRange?: Array<number>;
    assets?: Array<IAsset>;
}
/**
 * @interface IAsset
 * @param {string} SeedId
 * @param {string} Name (optional)
 */
export interface IAsset {
    SeedId: string;
    Name?: string;
}
/**
 * @interface IGizmoSetting
 * @param {string} gizmoState (optional)
 * @param {string} gizmoCoordinateSystem (optional)
 * @param {boolean} bPreserveScaleRatio (optional)
 */
export interface IGizmoSetting {
    gizmoState?: string;
    gizmoCoordinateSystem?: string;
    bPreserveScaleRatio?: boolean;
}
